+            | "role_returns_master"
+            | "role_case_insensitive"
+            | "role_still_master_after_operations" => {
+                live_offsets.push(parse_master_role_reply(&failure.expected));
+                runtime_offsets.push(parse_master_role_reply(&failure.actual));
